Using `Math.random()` for security-sensitive operations like password reset tokens is extremely dangerous. `Math.random()` uses a predictable pseudo-random number generator (PRNG) that is NOT cryptographically secure.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Using Math.random() for security tokens
function generateResetToken() {
  let token = '';
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';

  for (let i = 0; i < 32; i++) {
    // VULNERABLE: Math.random() is predictable!
    token += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return token;
}

app.post('/api/forgot-password', (req, res) => {
  const email = req.body.email;
  const resetToken = generateResetToken();

  // Store token and send email
  storeResetToken(email, resetToken);
  sendResetEmail(email, resetToken);

  res.json({ message: 'Reset link sent' });
});

module.exports = app;
```

**Attack Scenario**:
```javascript
// Attacker can predict Math.random() state by:
// 1. Requesting multiple tokens and analyzing patterns
// 2. Exploiting the XorShift128+ algorithm used internally
// 3. Using tools like 'v8_rand_buster' to predict next values

// After observing ~600 consecutive outputs, attacker can predict future tokens
const predictedToken = predictNextMathRandom(observedOutputs);
// Attacker uses predicted token to reset victim's password
```

**Why This Is Dangerous**:
- `Math.random()` uses XorShift128+ algorithm which is mathematically predictable
- Internal state can be reconstructed from approximately 600 observed outputs
- Token generation timing can leak information about PRNG state
- No entropy source - purely algorithmic, seeded from system time at startup

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const app = express();

// SECURE: Using crypto.randomBytes() for cryptographically secure tokens
function generateSecureResetToken() {
  // crypto.randomBytes() uses OS-level CSPRNG
  // 32 bytes = 256 bits of entropy (industry standard)
  return crypto.randomBytes(32).toString('hex');
}

// Alternative: URL-safe base64 encoding
function generateSecureTokenBase64() {
  return crypto.randomBytes(32).toString('base64url');
}

app.post('/api/forgot-password', async (req, res) => {
  const email = req.body.email;

  try {
    // Generate cryptographically secure token
    const resetToken = generateSecureResetToken();

    // Hash the token before storing (defense in depth)
    const tokenHash = crypto
      .createHash('sha256')
      .update(resetToken)
      .digest('hex');

    // Store only the hash, set expiration
    await storeResetTokenHash(email, tokenHash, Date.now() + 3600000); // 1 hour

    // Send unhashed token to user
    await sendResetEmail(email, resetToken);

    res.json({ message: 'Reset link sent if email exists' });
  } catch (error) {
    console.error('Password reset error:', error);
    // Don't reveal if email exists
    res.json({ message: 'Reset link sent if email exists' });
  }
});

module.exports = app;
```

**Key Security Controls**:
- **crypto.randomBytes()**: Uses operating system's CSPRNG (/dev/urandom on Linux, CryptGenRandom on Windows)
- **Token hashing**: Store hashed token in database so database compromise doesn't expose valid tokens
- **Timing-safe response**: Same message whether email exists or not prevents enumeration

Excellent question! Session IDs and API keys have additional considerations beyond password reset tokens, including entropy requirements, rotation policies, and secure storage patterns.

**PRODUCTION PATTERN**:

```javascript
const crypto = require('crypto');
const { promisify } = require('util');

const randomBytesAsync = promisify(crypto.randomBytes);

class SecureTokenGenerator {
  /**
   * Generate cryptographically secure tokens for various purposes
   * Each type has specific entropy and format requirements
   */

  // Session ID: 128 bits minimum (OWASP recommendation)
  static async generateSessionId() {
    const bytes = await randomBytesAsync(32); // 256 bits for extra security
    return bytes.toString('hex');
  }

  // API Key: Longer, with prefix for identification
  static async generateApiKey(prefix = 'sk') {
    const bytes = await randomBytesAsync(32);
    const key = bytes.toString('base64url');
    // Format: prefix_randompart (similar to Stripe's sk_live_xxx)
    return `${prefix}_${key}`;
  }

  // Password reset token: Time-limited, single use
  static async generateResetToken() {
    const bytes = await randomBytesAsync(32);
    return bytes.toString('hex');
  }

  // CSRF token: Per-session, embedded in forms
  static async generateCsrfToken() {
    const bytes = await randomBytesAsync(32);
    return bytes.toString('base64url');
  }

  // Verification code: Shorter, user-friendly (6 digits)
  static async generateVerificationCode() {
    // Use rejection sampling for uniform distribution
    const bytes = await randomBytesAsync(4);
    const num = bytes.readUInt32BE(0);
    // Uniform distribution in range [0, 999999]
    const code = num % 1000000;
    return code.toString().padStart(6, '0');
  }
}

// Production session management with secure tokens
class SecureSessionManager {
  constructor(redisClient, options = {}) {
    this.redis = redisClient;
    this.sessionTTL = options.sessionTTL || 86400; // 24 hours
    this.maxSessions = options.maxSessions || 5; // Per user
    this.rotationInterval = options.rotationInterval || 900000; // 15 minutes
  }

  async createSession(userId, metadata = {}) {
    const sessionId = await SecureTokenGenerator.generateSessionId();

    // Hash session ID before using as Redis key (defense in depth)
    const sessionKey = this.hashSessionId(sessionId);

    const sessionData = {
      userId,
      createdAt: Date.now(),
      lastRotated: Date.now(),
      ip: metadata.ip,
      userAgent: metadata.userAgent,
      fingerprint: await this.generateFingerprint(metadata)
    };

    // Atomic operation: create session and add to user's session list
    const multi = this.redis.multi();
    multi.setex(`session:${sessionKey}`, this.sessionTTL, JSON.stringify(sessionData));
    multi.sadd(`user:${userId}:sessions`, sessionKey);
    multi.expire(`user:${userId}:sessions`, this.sessionTTL);
    await multi.exec();

    // Enforce max sessions per user
    await this.enforceSessionLimit(userId);

    // Audit log
    console.log(JSON.stringify({
      event: 'session_created',
      userId,
      sessionPrefix: sessionId.substring(0, 8),
      ip: metadata.ip,
      timestamp: new Date().toISOString()
    }));

    return sessionId; // Return unhashed ID to client
  }

  async validateSession(sessionId, metadata = {}) {
    const sessionKey = this.hashSessionId(sessionId);
    const data = await this.redis.get(`session:${sessionKey}`);

    if (!data) {
      return { valid: false, reason: 'session_not_found' };
    }

    const session = JSON.parse(data);

    // Check for session binding (optional strict mode)
    if (session.fingerprint) {
      const currentFingerprint = await this.generateFingerprint(metadata);
      if (!this.timingSafeCompare(session.fingerprint, currentFingerprint)) {
        // Possible session hijacking
        console.warn(JSON.stringify({
          event: 'session_fingerprint_mismatch',
          userId: session.userId,
          ip: metadata.ip,
          timestamp: new Date().toISOString()
        }));
        // Optionally invalidate session here
      }
    }

    // Rotate session ID if needed (sliding window)
    if (Date.now() - session.lastRotated > this.rotationInterval) {
      return await this.rotateSession(sessionId, session, metadata);
    }

    return { valid: true, userId: session.userId, sessionId };
  }

  async rotateSession(oldSessionId, sessionData, metadata) {
    // Generate new session ID
    const newSessionId = await SecureTokenGenerator.generateSessionId();
    const oldKey = this.hashSessionId(oldSessionId);
    const newKey = this.hashSessionId(newSessionId);

    sessionData.lastRotated = Date.now();

    // Atomic rotation
    const multi = this.redis.multi();
    multi.setex(`session:${newKey}`, this.sessionTTL, JSON.stringify(sessionData));
    multi.del(`session:${oldKey}`);
    multi.srem(`user:${sessionData.userId}:sessions`, oldKey);
    multi.sadd(`user:${sessionData.userId}:sessions`, newKey);
    await multi.exec();

    return { valid: true, userId: sessionData.userId, sessionId: newSessionId, rotated: true };
  }

  hashSessionId(sessionId) {
    return crypto.createHash('sha256').update(sessionId).digest('hex');
  }

  async generateFingerprint(metadata) {
    const data = `${metadata.userAgent || ''}|${metadata.acceptLanguage || ''}`;
    return crypto.createHash('sha256').update(data).digest('hex').substring(0, 16);
  }

  timingSafeCompare(a, b) {
    if (a.length !== b.length) return false;
    return crypto.timingSafeEqual(Buffer.from(a), Buffer.from(b));
  }

  async enforceSessionLimit(userId) {
    const sessions = await this.redis.smembers(`user:${userId}:sessions`);
    if (sessions.length > this.maxSessions) {
      // Remove oldest sessions
      const toRemove = sessions.slice(0, sessions.length - this.maxSessions);
      const multi = this.redis.multi();
      for (const sessionKey of toRemove) {
        multi.del(`session:${sessionKey}`);
        multi.srem(`user:${userId}:sessions`, sessionKey);
      }
      await multi.exec();
    }
  }

  async invalidateAllSessions(userId) {
    const sessions = await this.redis.smembers(`user:${userId}:sessions`);
    const multi = this.redis.multi();
    for (const sessionKey of sessions) {
      multi.del(`session:${sessionKey}`);
    }
    multi.del(`user:${userId}:sessions`);
    await multi.exec();

    console.log(JSON.stringify({
      event: 'all_sessions_invalidated',
      userId,
      count: sessions.length,
      timestamp: new Date().toISOString()
    }));
  }
}

module.exports = { SecureTokenGenerator, SecureSessionManager };
```

**Defense in Depth Layers**:

1. **Cryptographic randomness at every layer**:
```javascript
// Always use crypto module, never Math.random()
const crypto = require('crypto');

// For synchronous contexts (startup code only)
const syncToken = crypto.randomBytes(32).toString('hex');

// For async contexts (preferred in production)
const asyncToken = await promisify(crypto.randomBytes)(32);
```

2. **Token hashing before storage**:
```javascript
// Never store raw tokens in database
const storedValue = crypto
  .createHash('sha256')
  .update(rawToken)
  .digest('hex');

// On validation, hash the incoming token and compare
function validateToken(inputToken, storedHash) {
  const inputHash = crypto
    .createHash('sha256')
    .update(inputToken)
    .digest('hex');
  return crypto.timingSafeEqual(
    Buffer.from(inputHash),
    Buffer.from(storedHash)
  );
}
```

3. **Timing-safe comparisons**:
```javascript
// WRONG: Vulnerable to timing attacks
if (userToken === storedToken) { /* ... */ }

// CORRECT: Constant-time comparison
function secureCompare(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(Buffer.from(a), Buffer.from(b));
}
```

**Additional Protections**:
- **Rate limiting**: Limit token validation attempts to prevent brute force
- **Token expiration**: Always set TTLs, never use permanent tokens for sensitive operations
- **Audit logging**: Log all token generation and validation for forensics
- **Session binding**: Optionally bind sessions to IP/user-agent fingerprint
- **Automatic rotation**: Rotate long-lived tokens periodically to limit exposure window
- **Secure transmission**: Always use HTTPS, set Secure flag on session cookies

Using `java.util.Random` for security-sensitive operations like password reset tokens is **critically dangerous**. This class uses a Linear Congruential Generator (LCG) that is predictable and can be completely reversed by an attacker who observes just a few outputs.

**VULNERABLE CODE**:

```java
import java.util.Random;
import java.util.Base64;

public class PasswordResetService {

    // VULNERABLE: Using predictable PRNG for security tokens
    private Random random = new Random();

    public String generateResetToken() {
        // DANGEROUS: java.util.Random is not cryptographically secure
        byte[] tokenBytes = new byte[32];
        for (int i = 0; i < tokenBytes.length; i++) {
            tokenBytes[i] = (byte) random.nextInt(256);
        }
        return Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }

    public String generateResetTokenSimple() {
        // EVEN WORSE: Easily predictable 6-digit code
        int code = random.nextInt(999999);
        return String.format("%06d", code);
    }

    // Using System.currentTimeMillis() as seed makes it trivially predictable
    public String generateTimestampedToken() {
        Random seededRandom = new Random(System.currentTimeMillis());
        return Long.toHexString(seededRandom.nextLong());
    }
}
```

**Attack Payload**:
```java
// Attacker code to predict Random outputs
import java.util.Random;

public class RandomCracker {
    // Given two consecutive nextInt() outputs, recover the seed
    public static long crackSeed(int output1, int output2) {
        long multiplier = 0x5DEECE66DL;
        long addend = 0xBL;
        long mask = (1L << 48) - 1;

        // Brute force the lower 16 bits
        for (int i = 0; i < 65536; i++) {
            long seed = ((long) output1 << 16) + i;
            if ((((seed * multiplier + addend) & mask) >>> 16) == output2) {
                return seed;
            }
        }
        return -1;
    }

    public static void main(String[] args) {
        // Once seed is known, predict ALL future tokens
        long crackedSeed = crackSeed(observedValue1, observedValue2);
        Random predictedRandom = new Random();
        // Use reflection to set internal seed
        // All future outputs are now predictable
    }
}
```

**Why This Is Dangerous**:
- `java.util.Random` uses a 48-bit LCG algorithm that can be reversed with just 2 observed outputs
- The internal state can be recovered and all future/past values predicted
- Time-based seeds reduce entropy to seconds/milliseconds, trivially brute-forceable
- Attackers can request multiple tokens, analyze patterns, and predict valid tokens for other users

**SECURE VERSION**:

```java
import java.security.SecureRandom;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;
import java.util.logging.Logger;

public class SecurePasswordResetService {

    private static final Logger logger = Logger.getLogger(SecurePasswordResetService.class.getName());
    private static final int TOKEN_BYTE_LENGTH = 32; // 256 bits of entropy

    // SECURE: Use cryptographically strong random number generator
    private final SecureRandom secureRandom;

    public SecurePasswordResetService() throws NoSuchAlgorithmException {
        // Use strongest available algorithm
        this.secureRandom = SecureRandom.getInstanceStrong();
        logger.info("Initialized SecureRandom with algorithm: " + secureRandom.getAlgorithm());
    }

    public String generateResetToken() {
        // Generate cryptographically secure random bytes
        byte[] tokenBytes = new byte[TOKEN_BYTE_LENGTH];
        secureRandom.nextBytes(tokenBytes);

        // URL-safe Base64 encoding without padding
        String token = Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);

        logger.fine("Generated secure reset token (length: " + token.length() + ")");
        return token;
    }

    public String generateSecureNumericCode(int digits) {
        if (digits < 6 || digits > 12) {
            throw new IllegalArgumentException("Digits must be between 6 and 12");
        }

        // Calculate max value for uniform distribution
        long maxValue = (long) Math.pow(10, digits);
        long randomValue = Math.abs(secureRandom.nextLong()) % maxValue;

        return String.format("%0" + digits + "d", randomValue);
    }
}
```

**Key Security Controls**:
- **SecureRandom.getInstanceStrong()**: Uses the strongest available CSPRNG (typically SHA1PRNG or NativePRNG backed by /dev/random)
- **256-bit tokens**: Provides 2^256 possible combinations, computationally infeasible to brute force
- **URL-safe Base64**: Ensures tokens work in URLs without encoding issues
- **No predictable seeding**: SecureRandom self-seeds from OS entropy sources

Key and IV generation requires extra care beyond just using SecureRandom. You need proper key derivation, secure storage, and correct IV handling to prevent cryptographic attacks.

**PRODUCTION PATTERN**:

```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.PBEKeySpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.security.spec.InvalidKeySpecException;
import java.util.Arrays;
import java.util.Base64;
import java.util.logging.Logger;

public class SecureCryptoKeyService {

    private static final Logger logger = Logger.getLogger(SecureCryptoKeyService.class.getName());

    // Cryptographic constants
    private static final String KEY_ALGORITHM = "AES";
    private static final String CIPHER_ALGORITHM = "AES/GCM/NoPadding";
    private static final int AES_KEY_SIZE = 256;
    private static final int GCM_IV_LENGTH = 12;  // 96 bits per NIST recommendation
    private static final int GCM_TAG_LENGTH = 128; // Authentication tag bits

    // PBKDF2 parameters for password-based key derivation
    private static final String PBKDF2_ALGORITHM = "PBKDF2WithHmacSHA256";
    private static final int PBKDF2_ITERATIONS = 310000; // OWASP 2023 recommendation
    private static final int SALT_LENGTH = 16; // 128 bits

    private final SecureRandom secureRandom;

    public SecureCryptoKeyService() throws NoSuchAlgorithmException {
        this.secureRandom = SecureRandom.getInstanceStrong();

        // Force initial seeding to avoid blocking during critical operations
        byte[] seed = new byte[32];
        this.secureRandom.nextBytes(seed);
        logger.info("SecureCryptoKeyService initialized with " + secureRandom.getAlgorithm());
    }

    /**
     * Generate a cryptographically secure AES key using KeyGenerator.
     * This is the preferred method for generating random symmetric keys.
     */
    public SecretKey generateAESKey() throws NoSuchAlgorithmException {
        KeyGenerator keyGenerator = KeyGenerator.getInstance(KEY_ALGORITHM);
        keyGenerator.init(AES_KEY_SIZE, secureRandom);

        SecretKey key = keyGenerator.generateKey();
        logger.info("Generated new AES-" + AES_KEY_SIZE + " key");
        return key;
    }

    /**
     * Generate a unique IV for each encryption operation.
     * CRITICAL: Never reuse IVs with the same key in GCM mode.
     */
    public byte[] generateIV() {
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);
        return iv;
    }

    /**
     * Derive encryption key from password using PBKDF2.
     * Used when encryption key must be derived from user password.
     */
    public KeyDerivationResult deriveKeyFromPassword(char[] password) 
            throws NoSuchAlgorithmException, InvalidKeySpecException {

        // Generate random salt
        byte[] salt = new byte[SALT_LENGTH];
        secureRandom.nextBytes(salt);

        // Derive key using PBKDF2
        PBEKeySpec spec = new PBEKeySpec(password, salt, PBKDF2_ITERATIONS, AES_KEY_SIZE);
        SecretKeyFactory factory = SecretKeyFactory.getInstance(PBKDF2_ALGORITHM);
        byte[] keyBytes = factory.generateSecret(spec).getEncoded();

        // Clear sensitive data from memory
        spec.clearPassword();

        SecretKey derivedKey = new SecretKeySpec(keyBytes, KEY_ALGORITHM);

        // Clear the key bytes array
        Arrays.fill(keyBytes, (byte) 0);

        logger.info("Derived key using PBKDF2 with " + PBKDF2_ITERATIONS + " iterations");
        return new KeyDerivationResult(derivedKey, salt);
    }

    /**
     * Encrypt data with AES-GCM providing confidentiality and authenticity.
     */
    public EncryptedData encrypt(byte[] plaintext, SecretKey key) throws Exception {
        // Generate fresh IV for each encryption
        byte[] iv = generateIV();

        Cipher cipher = Cipher.getInstance(CIPHER_ALGORITHM);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, key, gcmSpec);

        byte[] ciphertext = cipher.doFinal(plaintext);

        logger.fine("Encrypted " + plaintext.length + " bytes");
        return new EncryptedData(ciphertext, iv);
    }

    /**
     * Decrypt and verify authenticity of AES-GCM encrypted data.
     */
    public byte[] decrypt(EncryptedData encryptedData, SecretKey key) throws Exception {
        Cipher cipher = Cipher.getInstance(CIPHER_ALGORITHM);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, encryptedData.iv);
        cipher.init(Cipher.DECRYPT_MODE, key, gcmSpec);

        byte[] plaintext = cipher.doFinal(encryptedData.ciphertext);

        logger.fine("Decrypted " + plaintext.length + " bytes");
        return plaintext;
    }

    // Result classes for returning multiple values
    public static class KeyDerivationResult {
        public final SecretKey key;
        public final byte[] salt;

        public KeyDerivationResult(SecretKey key, byte[] salt) {
            this.key = key;
            this.salt = salt;
        }
    }

    public static class EncryptedData {
        public final byte[] ciphertext;
        public final byte[] iv;

        public EncryptedData(byte[] ciphertext, byte[] iv) {
            this.ciphertext = ciphertext;
            this.iv = iv;
        }

        // Serialize IV + ciphertext for storage
        public byte[] toBytes() {
            byte[] result = new byte[iv.length + ciphertext.length];
            System.arraycopy(iv, 0, result, 0, iv.length);
            System.arraycopy(ciphertext, 0, result, iv.length, ciphertext.length);
            return result;
        }

        // Deserialize from stored format
        public static EncryptedData fromBytes(byte[] data, int ivLength) {
            byte[] iv = Arrays.copyOfRange(data, 0, ivLength);
            byte[] ciphertext = Arrays.copyOfRange(data, ivLength, data.length);
            return new EncryptedData(ciphertext, iv);
        }
    }
}
```

**Defense in Depth Layers**:

1. **Secure Random Source with Initialization**:
```java
// Force entropy gathering at startup, not during critical operations
private final SecureRandom secureRandom;

public void initialize() throws NoSuchAlgorithmException {
    this.secureRandom = SecureRandom.getInstanceStrong();
    // Pre-generate entropy to avoid blocking
    byte[] warmup = new byte[64];
    this.secureRandom.nextBytes(warmup);
    Arrays.fill(warmup, (byte) 0); // Clear warmup bytes
}
```

2. **IV Uniqueness Enforcement**:
```java
import java.util.concurrent.atomic.AtomicLong;
import java.nio.ByteBuffer;

public class IVGenerator {
    private final SecureRandom secureRandom;
    private final AtomicLong counter = new AtomicLong(0);
    private final byte[] randomPrefix;

    public IVGenerator() throws NoSuchAlgorithmException {
        this.secureRandom = SecureRandom.getInstanceStrong();
        // 8 bytes random prefix + 4 byte counter = 12 byte IV
        this.randomPrefix = new byte[8];
        this.secureRandom.nextBytes(randomPrefix);
    }

    // Counter-based IV guarantees uniqueness even under high load
    public byte[] generateUniqueIV() {
        long count = counter.incrementAndGet();
        ByteBuffer buffer = ByteBuffer.allocate(12);
        buffer.put(randomPrefix);
        buffer.putInt((int) count);
        return buffer.array();
    }
}
```

3. **Secure Key Storage with HSM Integration**:
```java
import java.security.KeyStore;
import javax.crypto.SecretKey;

public class SecureKeyStorage {
    private static final String KEYSTORE_TYPE = "PKCS11"; // For HSM
    private static final String KEY_ALIAS = "encryption-master-key";

    public SecretKey loadOrGenerateKey(String keystorePath, char[] password) 
            throws Exception {

        KeyStore keyStore = KeyStore.getInstance(KEYSTORE_TYPE);
        keyStore.load(null, password);

        if (keyStore.containsAlias(KEY_ALIAS)) {
            return (SecretKey) keyStore.getKey(KEY_ALIAS, password);
        }

        // Generate and store new key
        SecretKey newKey = generateAESKey();
        KeyStore.SecretKeyEntry entry = new KeyStore.SecretKeyEntry(newKey);
        keyStore.setEntry(KEY_ALIAS, entry, 
            new KeyStore.PasswordProtection(password));

        return newKey;
    }
}
```

**Additional Protections**:

- **Memory Security**: Clear sensitive byte arrays after use with `Arrays.fill(keyBytes, (byte) 0)` - prevents memory dumps from exposing keys
- **Key Rotation**: Implement automatic key rotation every 90 days or after encrypting 2^32 blocks (GCM limit)
- **Monitoring**: Log all key generation events with correlation IDs for audit trails, alert on anomalous key generation patterns
- **Algorithm Agility**: Use constants for algorithm names to enable quick updates if vulnerabilities are discovered
- **FIPS Compliance**: For regulated environments, use `SecureRandom.getInstance("SHA1PRNG", "SunPKCS11-NSS")` with FIPS-validated provider
- **Entropy Monitoring**: In production, monitor `/proc/sys/kernel/random/entropy_avail` on Linux to ensure sufficient system entropy

Using `math/rand` for session tokens is one of the most dangerous cryptographic mistakes in Go. The `math/rand` package generates predictable pseudo-random numbers that attackers can easily predict and exploit.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/hex"
	"fmt"
	"math/rand"
	"net/http"
	"time"
)

var sessions = make(map[string]string)

func init() {
	// DANGEROUS: Seeding with time is predictable
	rand.Seed(time.Now().UnixNano())
}

func generateSessionToken() string {
	// VULNERABLE: math/rand is not cryptographically secure
	b := make([]byte, 32)
	for i := range b {
		b[i] = byte(rand.Intn(256))
	}
	return hex.EncodeToString(b)
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	// Assume authentication succeeded

	token := generateSessionToken()
	sessions[token] = username

	http.SetCookie(w, &http.Cookie{
		Name:  "session",
		Value: token,
	})
	fmt.Fprintf(w, "Logged in as %s", username)
}
```

**Attack Payload**:
```go
// Attacker can predict tokens by:
// 1. Knowing approximate server start time (seed)
// 2. Observing a few tokens to reconstruct PRNG state
package main

import (
	"math/rand"
	"time"
)

func predictNextToken(observedTime int64) {
	// Brute force seed within time window
	for seed := observedTime - 1000000000; seed <= observedTime; seed++ {
		rand.Seed(seed)
		// Generate and test tokens
	}
}
```

**Why This Is Dangerous**:
- `math/rand` uses a deterministic algorithm (linear congruential generator)
- Time-based seeds have very low entropy (~30 bits for nanoseconds in realistic windows)
- An attacker observing any token can reconstruct the internal state and predict all future tokens
- Session hijacking becomes trivial once the PRNG state is recovered

**SECURE VERSION**:

```go
package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
)

var (
	sessions     = make(map[string]string)
	sessionsLock sync.RWMutex
)

// generateSecureToken creates a cryptographically secure random token
func generateSecureToken(length int) (string, error) {
	// SECURE: crypto/rand uses OS entropy source
	b := make([]byte, length)
	_, err := io.ReadFull(rand.Reader, b)
	if err != nil {
		return "", fmt.Errorf("failed to generate random bytes: %w", err)
	}
	// URL-safe base64 encoding
	return base64.URLEncoding.EncodeToString(b), nil
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	// Assume authentication succeeded

	// Generate 32 bytes = 256 bits of entropy
	token, err := generateSecureToken(32)
	if err != nil {
		log.Printf("Token generation failed: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	sessionsLock.Lock()
	sessions[token] = username
	sessionsLock.Unlock()

	http.SetCookie(w, &http.Cookie{
		Name:     "session",
		Value:    token,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
	})
	fmt.Fprintf(w, "Logged in as %s", username)
}
```

**Key Security Controls**:
- **crypto/rand.Reader**: Uses OS-level CSPRNG (/dev/urandom on Linux, CryptGenRandom on Windows)
- **256-bit tokens**: Provides 2^256 possible values, making brute force infeasible
- **io.ReadFull()**: Ensures all requested bytes are read, fails safely if entropy is unavailable
- **Secure cookie flags**: HttpOnly prevents XSS token theft, Secure ensures HTTPS only

For API keys and production systems, you need additional considerations: secure storage with hashing, proper key formatting, rate limiting on generation, and monitoring for anomalies.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"crypto/subtle"
	"encoding/base64"
	"encoding/hex"
	"fmt"
	"io"
	"log"
	"sync"
	"time"

	"golang.org/x/crypto/argon2"
	"golang.org/x/time/rate"
)

const (
	APIKeyLength     = 32  // 256 bits
	APIKeyPrefix     = "sk_live_"
	Argon2Time       = 1
	Argon2Memory     = 64 * 1024
	Argon2Threads    = 4
	Argon2KeyLen     = 32
)

type APIKey struct {
	ID           string
	Prefix       string    // Visible prefix for identification
	HashedKey    []byte    // Argon2 hash of full key
	Salt         []byte
	CreatedAt    time.Time
	LastUsedAt   *time.Time
	RateLimitRPS int
}

type SecureKeyManager struct {
	mu           sync.RWMutex
	keys         map[string]*APIKey
	generateLimiter *rate.Limiter
	logger       *log.Logger
}

func NewSecureKeyManager(logger *log.Logger) *SecureKeyManager {
	return &SecureKeyManager{
		keys:            make(map[string]*APIKey),
		generateLimiter: rate.NewLimiter(rate.Limit(10), 5), // 10/sec, burst 5
		logger:          logger,
	}
}

// GenerateAPIKey creates a new API key with cryptographically secure randomness
func (km *SecureKeyManager) GenerateAPIKey(ctx context.Context, userID string) (string, error) {
	// Rate limit key generation to prevent abuse
	if err := km.generateLimiter.Wait(ctx); err != nil {
		km.logger.Printf("SECURITY: Rate limit exceeded for API key generation, user=%s", userID)
		return "", fmt.Errorf("rate limit exceeded")
	}

	// Generate cryptographically secure random bytes
	keyBytes := make([]byte, APIKeyLength)
	if _, err := io.ReadFull(rand.Reader, keyBytes); err != nil {
		km.logger.Printf("CRITICAL: Entropy source failed: %v", err)
		return "", fmt.Errorf("failed to generate secure key: %w", err)
	}

	// Generate unique salt for this key
	salt := make([]byte, 16)
	if _, err := io.ReadFull(rand.Reader, salt); err != nil {
		return "", fmt.Errorf("failed to generate salt: %w", err)
	}

	// Create the full API key with prefix
	fullKey := APIKeyPrefix + base64.URLEncoding.EncodeToString(keyBytes)

	// Generate short ID for lookup (first 8 chars of hash)
	idHash := sha256.Sum256([]byte(fullKey))
	keyID := hex.EncodeToString(idHash[:4])

	// Hash the key for storage using Argon2id
	hashedKey := argon2.IDKey(
		[]byte(fullKey),
		salt,
		Argon2Time,
		Argon2Memory,
		Argon2Threads,
		Argon2KeyLen,
	)

	apiKey := &APIKey{
		ID:           keyID,
		Prefix:       fullKey[:12], // Store visible prefix for UI
		HashedKey:    hashedKey,
		Salt:         salt,
		CreatedAt:    time.Now().UTC(),
		RateLimitRPS: 100,
	}

	km.mu.Lock()
	km.keys[keyID] = apiKey
	km.mu.Unlock()

	km.logger.Printf("AUDIT: API key generated, id=%s, user=%s, prefix=%s",
		keyID, userID, apiKey.Prefix)

	// Return full key ONLY ONCE - it cannot be recovered
	return fullKey, nil
}

// ValidateAPIKey verifies a key using constant-time comparison
func (km *SecureKeyManager) ValidateAPIKey(ctx context.Context, providedKey string) (*APIKey, error) {
	// Quick format validation
	if len(providedKey) < len(APIKeyPrefix)+10 {
		return nil, fmt.Errorf("invalid key format")
	}

	// Find key by ID hash
	idHash := sha256.Sum256([]byte(providedKey))
	keyID := hex.EncodeToString(idHash[:4])

	km.mu.RLock()
	apiKey, exists := km.keys[keyID]
	km.mu.RUnlock()

	if !exists {
		// Perform dummy hash to prevent timing attacks
		_ = argon2.IDKey([]byte(providedKey), make([]byte, 16),
			Argon2Time, Argon2Memory, Argon2Threads, Argon2KeyLen)
		return nil, fmt.Errorf("invalid API key")
	}

	// Hash provided key with stored salt
	computedHash := argon2.IDKey(
		[]byte(providedKey),
		apiKey.Salt,
		Argon2Time,
		Argon2Memory,
		Argon2Threads,
		Argon2KeyLen,
	)

	// Constant-time comparison prevents timing attacks
	if subtle.ConstantTimeCompare(computedHash, apiKey.HashedKey) != 1 {
		km.logger.Printf("SECURITY: Invalid API key attempt, id=%s", keyID)
		return nil, fmt.Errorf("invalid API key")
	}

	// Update last used timestamp
	now := time.Now().UTC()
	km.mu.Lock()
	apiKey.LastUsedAt = &now
	km.mu.Unlock()

	return apiKey, nil
}

// MonitorEntropyHealth checks CSPRNG availability
func (km *SecureKeyManager) MonitorEntropyHealth() error {
	testBytes := make([]byte, 32)
	start := time.Now()

	if _, err := io.ReadFull(rand.Reader, testBytes); err != nil {
		km.logger.Printf("CRITICAL: Entropy source unhealthy: %v", err)
		return err
	}

	elapsed := time.Since(start)
	if elapsed > 100*time.Millisecond {
		km.logger.Printf("WARNING: Slow entropy generation: %v", elapsed)
	}

	return nil
}
```

**Defense in Depth Layers**:

1. **Cryptographically Secure Generation**:
```go
// Always use crypto/rand, never math/rand
keyBytes := make([]byte, 32)
_, err := io.ReadFull(rand.Reader, keyBytes)
// io.ReadFull ensures we get ALL requested entropy or fail
```

2. **Secure Storage with Argon2id Hashing**:
```go
// Never store raw API keys - hash them like passwords
hashedKey := argon2.IDKey(
	[]byte(fullKey),
	salt,           // Unique salt per key
	1,              // Time parameter
	64*1024,        // Memory in KB
	4,              // Parallelism
	32,             // Output length
)
```

3. **Constant-Time Validation**:
```go
// Prevent timing attacks during key comparison
if subtle.ConstantTimeCompare(computedHash, storedHash) != 1 {
	return nil, fmt.Errorf("invalid key")
}
```

**Additional Protections**:
- **Rate limiting on generation**: Prevents mass key generation attacks
- **Audit logging**: All key operations logged with timestamps and user context
- **Key prefixes**: Allow identification without revealing the secret (e.g., `sk_live_...`)
- **Entropy monitoring**: Health checks ensure CSPRNG availability
- **One-time display**: API keys shown only at creation, never retrievable afterward
- **Argon2id over bcrypt**: Memory-hard algorithm resistant to GPU/ASIC attacks
- **Timing attack prevention**: Dummy hash computation for non-existent keys

