Excellent questions. Production API key generation requires additional considerations: format validation, entropy verification, key derivation for prefixes, and resilient error handling. Let me show you a production-grade implementation.

**PRODUCTION PATTERN**:

```go
package apikeys

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base32"
	"encoding/hex"
	"errors"
	"fmt"
	"io"
	"log"
	"strings"
	"sync"
	"time"
)

var (
	ErrEntropyExhausted = errors.New("system entropy source exhausted")
	ErrInvalidKeyFormat = errors.New("invalid API key format")
)

// APIKey represents a structured API key with metadata
type APIKey struct {
	Prefix    string    // Human-readable prefix (e.g., "sk_live_")
	Secret    string    // The actual secret portion
	Checksum  string    // Verification checksum
	CreatedAt time.Time
	Hash      string    // For storage (never store raw key)
}

// APIKeyGenerator provides secure API key generation with monitoring
type APIKeyGenerator struct {
	prefix         string
	entropyBytes   int
	mu             sync.Mutex
	generationCount int64
	failureCount    int64
	lastFailure     time.Time
}

// NewAPIKeyGenerator creates a new generator with specified prefix
func NewAPIKeyGenerator(prefix string, entropyBytes int) *APIKeyGenerator {
	if entropyBytes < 24 {
		entropyBytes = 32 // Minimum 256 bits
	}
	return &APIKeyGenerator{
		prefix:       prefix,
		entropyBytes: entropyBytes,
	}
}

// generateSecureBytes reads cryptographically secure random bytes
// with retry logic and entropy validation
func (g *APIKeyGenerator) generateSecureBytes(length int) ([]byte, error) {
	const maxRetries = 3
	const retryDelay = 100 * time.Millisecond

	bytes := make([]byte, length)

	for attempt := 0; attempt < maxRetries; attempt++ {
		n, err := io.ReadFull(rand.Reader, bytes)
		if err == nil && n == length {
			// Validate entropy: check for obviously non-random output
			if g.validateEntropy(bytes) {
				return bytes, nil
			}
			log.Printf("WARN: Low entropy detected, regenerating (attempt %d)", attempt+1)
		}

		if err != nil {
			log.Printf("ERROR: Random generation failed (attempt %d): %v", attempt+1, err)
		}

		time.Sleep(retryDelay)
	}

	g.mu.Lock()
	g.failureCount++
	g.lastFailure = time.Now()
	g.mu.Unlock()

	return nil, ErrEntropyExhausted
}

// validateEntropy performs basic entropy checks
func (g *APIKeyGenerator) validateEntropy(bytes []byte) bool {
	if len(bytes) < 16 {
		return false
	}

	// Check for all zeros or all ones (catastrophic failure)
	allZero := true
	allOne := true
	for _, b := range bytes {
		if b != 0 {
			allZero = false
		}
		if b != 0xFF {
			allOne = false
		}
	}

	if allZero || allOne {
		log.Printf("CRITICAL: Zero entropy detected - possible RNG failure")
		return false
	}

	// Basic frequency check: count unique bytes
	uniqueByes := make(map[byte]struct{})
	for _, b := range bytes {
		uniqueByes[b] = struct{}{}
	}

	// For 32 bytes, expect at least 16 unique values (very conservative)
	minUnique := len(bytes) / 2
	if len(uniqueByes) < minUnique {
		log.Printf("WARN: Suspicious byte distribution: %d unique in %d bytes", 
			len(uniqueByes), len(bytes))
		return false
	}

	return true
}

// Generate creates a new API key with the format: prefix_secret_checksum
func (g *APIKeyGenerator) Generate() (*APIKey, error) {
	// Generate secret bytes
	secretBytes, err := g.generateSecureBytes(g.entropyBytes)
	if err != nil {
		return nil, fmt.Errorf("failed to generate secret: %w", err)
	}

	// Encode using base32 (case-insensitive, no confusing chars)
	encoding := base32.StdEncoding.WithPadding(base32.NoPadding)
	secret := strings.ToLower(encoding.EncodeToString(secretBytes))

	// Generate checksum (last 6 chars of SHA256)
	fullKey := g.prefix + secret
	checksum := g.computeChecksum(fullKey)

	// Compute hash for storage (NEVER store raw key)
	hash := g.hashForStorage(fullKey + "_" + checksum)

	g.mu.Lock()
	g.generationCount++
	g.mu.Unlock()

	return &APIKey{
		Prefix:    g.prefix,
		Secret:    secret,
		Checksum:  checksum,
		CreatedAt: time.Now().UTC(),
		Hash:      hash,
	}, nil
}

// computeChecksum generates a 6-character checksum for validation
func (g *APIKeyGenerator) computeChecksum(data string) string {
	hash := sha256.Sum256([]byte(data))
	return hex.EncodeToString(hash[:])[:6]
}

// hashForStorage creates a SHA-256 hash suitable for database storage
func (g *APIKeyGenerator) hashForStorage(key string) string {
	hash := sha256.Sum256([]byte(key))
	return hex.EncodeToString(hash[:])
}

// FormatKey returns the full API key string
func (k *APIKey) FormatKey() string {
	return fmt.Sprintf("%s%s_%s", k.Prefix, k.Secret, k.Checksum)
}

// ValidateFormat checks if a key string has valid structure
func (g *APIKeyGenerator) ValidateFormat(key string) error {
	if !strings.HasPrefix(key, g.prefix) {
		return fmt.Errorf("%w: invalid prefix", ErrInvalidKeyFormat)
	}

	// Remove prefix
	rest := strings.TrimPrefix(key, g.prefix)

	// Split secret and checksum
	parts := strings.Split(rest, "_")
	if len(parts) != 2 {
		return fmt.Errorf("%w: missing checksum separator", ErrInvalidKeyFormat)
	}

	secret, checksum := parts[0], parts[1]

	// Validate checksum
	expectedChecksum := g.computeChecksum(g.prefix + secret)
	if checksum != expectedChecksum {
		return fmt.Errorf("%w: checksum mismatch", ErrInvalidKeyFormat)
	}

	return nil
}

// GetMetrics returns generator health metrics
func (g *APIKeyGenerator) GetMetrics() map[string]interface{} {
	g.mu.Lock()
	defer g.mu.Unlock()

	return map[string]interface{}{
		"generation_count": g.generationCount,
		"failure_count":    g.failureCount,
		"last_failure":     g.lastFailure,
		"health":           g.failureCount == 0 || time.Since(g.lastFailure) > time.Hour,
	}
}
```

