```

Using `System.Random` for security-sensitive tokens like password reset links is extremely dangerous and can lead to complete account takeover attacks.

**VULNERABLE CODE**:

```csharp
using System;
using System.Text;

namespace MyApp.Services
{
    public class TokenService
    {
        private static readonly Random _random = new Random();

        public string GeneratePasswordResetToken()
        {
            // VULNERABLE: System.Random is predictable!
            const string chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
            var token = new StringBuilder();

            for (int i = 0; i < 32; i++)
            {
                token.Append(chars[_random.Next(chars.Length)]);
            }

            return token.ToString();
        }

        public string GenerateSessionId()
        {
            // VULNERABLE: Predictable session IDs
            return _random.Next(100000000, 999999999).ToString();
        }
    }
}
```

**Attack Method**:
```csharp
// Attacker can predict tokens by:
// 1. Requesting multiple reset tokens
// 2. Using timestamp correlation to determine seed
// 3. Reproducing the Random instance state

// If attacker knows approximate server time:
var guessedSeed = (int)(DateTime.Now.Ticks & 0xFFFFFFFF);
var attackerRandom = new Random(guessedSeed);
// Now attacker can generate same sequence as server
```

**Why This Is Dangerous**:
- `System.Random` uses a predictable algorithm (linear congruential generator)
- Default seed is based on system time, which can be guessed within milliseconds
- Given a few outputs, the entire internal state can be reverse-engineered
- Attackers can predict all future tokens and reset any user's password

**SECURE VERSION**:

```csharp
using System;
using System.Security.Cryptography;

namespace MyApp.Services
{
    public class SecureTokenService
    {
        public string GeneratePasswordResetToken()
        {
            // SECURE: Cryptographically secure random bytes
            byte[] tokenBytes = new byte[32];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(tokenBytes);
            }

            // URL-safe Base64 encoding for use in links
            return Convert.ToBase64String(tokenBytes)
                .Replace("+", "-")
                .Replace("/", "_")
                .TrimEnd('=');
        }

        public string GenerateSessionId()
        {
            // SECURE: 256-bit cryptographic session ID
            byte[] sessionBytes = new byte[32];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(sessionBytes);
            }

            return BitConverter.ToString(sessionBytes).Replace("-", "").ToLower();
        }
    }
}
```

**Key Security Controls**:
- **RandomNumberGenerator.Create()**: Uses the operating system's CSPRNG (Windows CNG on Windows, /dev/urandom on Linux)
- **32 bytes (256 bits)**: Provides 2^256 possible values, making brute force infeasible
- **URL-safe encoding**: Ensures tokens work in URLs without encoding issues

For production API keys and OAuth tokens, you need a comprehensive approach that includes secure generation, proper storage with hashing, expiration management, and audit logging.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace MyApp.Security
{
    public class TokenConfiguration
    {
        public int ApiKeyLengthBytes { get; set; } = 32;
        public int RefreshTokenLengthBytes { get; set; } = 64;
        public int AccessTokenExpirationMinutes { get; set; } = 15;
        public int RefreshTokenExpirationDays { get; set; } = 30;
        public int PasswordResetExpirationMinutes { get; set; } = 60;
    }

    public class SecureTokenResult
    {
        public string PlainTextToken { get; set; }
        public string HashedToken { get; set; }
        public DateTime ExpiresAt { get; set; }
        public string TokenId { get; set; }
    }

    public interface ISecureTokenService
    {
        SecureTokenResult GenerateApiKey(string userId, string[] scopes);
        SecureTokenResult GenerateRefreshToken(string userId);
        SecureTokenResult GeneratePasswordResetToken(string userId);
        bool ValidateTokenHash(string plainTextToken, string storedHash);
    }

    public class ProductionTokenService : ISecureTokenService
    {
        private readonly TokenConfiguration _config;
        private readonly ILogger<ProductionTokenService> _logger;
        private readonly ITokenRepository _repository;
        private const int SaltSize = 16;
        private const int HashIterations = 100000;
        private const int HashSize = 32;

        public ProductionTokenService(
            IOptions<TokenConfiguration> config,
            ILogger<ProductionTokenService> logger,
            ITokenRepository repository)
        {
            _config = config.Value;
            _logger = logger;
            _repository = repository;
        }

        public SecureTokenResult GenerateApiKey(string userId, string[] scopes)
        {
            // Generate cryptographically secure token
            var tokenBytes = GenerateSecureBytes(_config.ApiKeyLengthBytes);
            var tokenId = GenerateTokenId();

            // Create the plain text token with prefix for identification
            var plainTextToken = $"myapp_{tokenId}_{Convert.ToBase64String(tokenBytes)
                .Replace("+", "-")
                .Replace("/", "_")
                .TrimEnd('=')}";

            // Hash the token for storage (never store plain text!)
            var hashedToken = HashToken(plainTextToken);

            // API keys don't expire by default but should be rotatable
            var result = new SecureTokenResult
            {
                PlainTextToken = plainTextToken,
                HashedToken = hashedToken,
                ExpiresAt = DateTime.MaxValue,
                TokenId = tokenId
            };

            // Audit log the generation (never log the plain text token)
            _logger.LogInformation(
                "API key generated for user {UserId}, TokenId: {TokenId}, Scopes: {Scopes}",
                userId, tokenId, string.Join(",", scopes));

            return result;
        }

        public SecureTokenResult GenerateRefreshToken(string userId)
        {
            var tokenBytes = GenerateSecureBytes(_config.RefreshTokenLengthBytes);
            var tokenId = GenerateTokenId();

            var plainTextToken = Convert.ToBase64String(tokenBytes)
                .Replace("+", "-")
                .Replace("/", "_")
                .TrimEnd('=');

            var hashedToken = HashToken(plainTextToken);
            var expiresAt = DateTime.UtcNow.AddDays(_config.RefreshTokenExpirationDays);

            var result = new SecureTokenResult
            {
                PlainTextToken = plainTextToken,
                HashedToken = hashedToken,
                ExpiresAt = expiresAt,
                TokenId = tokenId
            };

            _logger.LogInformation(
                "Refresh token generated for user {UserId}, TokenId: {TokenId}, ExpiresAt: {ExpiresAt}",
                userId, tokenId, expiresAt);

            return result;
        }

        public SecureTokenResult GeneratePasswordResetToken(string userId)
        {
            var tokenBytes = GenerateSecureBytes(32);
            var tokenId = GenerateTokenId();

            var plainTextToken = Convert.ToBase64String(tokenBytes)
                .Replace("+", "-")
                .Replace("/", "_")
                .TrimEnd('=');

            var hashedToken = HashToken(plainTextToken);
            var expiresAt = DateTime.UtcNow.AddMinutes(_config.PasswordResetExpirationMinutes);

            // Invalidate any existing reset tokens for this user
            _repository.InvalidateExistingResetTokens(userId);

            var result = new SecureTokenResult
            {
                PlainTextToken = plainTextToken,
                HashedToken = hashedToken,
                ExpiresAt = expiresAt,
                TokenId = tokenId
            };

            _logger.LogInformation(
                "Password reset token generated for user {UserId}, TokenId: {TokenId}, ExpiresAt: {ExpiresAt}",
                userId, tokenId, expiresAt);

            return result;
        }

        public bool ValidateTokenHash(string plainTextToken, string storedHash)
        {
            if (string.IsNullOrEmpty(plainTextToken) || string.IsNullOrEmpty(storedHash))
                return false;

            try
            {
                // Extract salt from stored hash
                var hashBytes = Convert.FromBase64String(storedHash);
                var salt = new byte[SaltSize];
                Array.Copy(hashBytes, 0, salt, 0, SaltSize);

                // Compute hash with same salt
                using (var pbkdf2 = new Rfc2898DeriveBytes(
                    plainTextToken, salt, HashIterations, HashAlgorithmName.SHA256))
                {
                    var computedHash = pbkdf2.GetBytes(HashSize);

                    // Constant-time comparison to prevent timing attacks
                    return CryptographicOperations.FixedTimeEquals(
                        computedHash,
                        new ReadOnlySpan<byte>(hashBytes, SaltSize, HashSize));
                }
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Token validation failed due to format error");
                return false;
            }
        }

        private byte[] GenerateSecureBytes(int length)
        {
            var bytes = new byte[length];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(bytes);
            }
            return bytes;
        }

        private string GenerateTokenId()
        {
            // Short identifier for logging/reference (not security-sensitive)
            var idBytes = GenerateSecureBytes(8);
            return Convert.ToBase64String(idBytes)
                .Replace("+", "")
                .Replace("/", "")
                .Substring(0, 8);
        }

        private string HashToken(string token)
        {
            // Use PBKDF2 with random salt for token storage
            var salt = GenerateSecureBytes(SaltSize);

            using (var pbkdf2 = new Rfc2898DeriveBytes(
                token, salt, HashIterations, HashAlgorithmName.SHA256))
            {
                var hash = pbkdf2.GetBytes(HashSize);

                // Combine salt + hash for storage
                var hashBytes = new byte[SaltSize + HashSize];
                Array.Copy(salt, 0, hashBytes, 0, SaltSize);
                Array.Copy(hash, 0, hashBytes, SaltSize, HashSize);

                return Convert.ToBase64String(hashBytes);
            }
        }
    }

    public interface ITokenRepository
    {
        void InvalidateExistingResetTokens(string userId);
        void StoreToken(string tokenId, string hashedToken, DateTime expiresAt, string userId);
    }
}
```

**Defense in Depth Layers**:

1. **Cryptographically Secure Generation**:
```csharp
// Uses OS-level CSPRNG via RandomNumberGenerator
using (var rng = RandomNumberGenerator.Create())
{
    rng.GetBytes(bytes); // Unpredictable, non-reproducible
}
```

2. **Secure Token Storage with Hashing**:
```csharp
// Never store tokens in plain text - use PBKDF2 with per-token salt
using (var pbkdf2 = new Rfc2898DeriveBytes(
    token, salt, 100000, HashAlgorithmName.SHA256))
{
    var hash = pbkdf2.GetBytes(32);
}
```

3. **Timing-Attack Resistant Comparison**:
```csharp
// Constant-time comparison prevents timing side-channel attacks
CryptographicOperations.FixedTimeEquals(computedHash, storedHash);
```

**Additional Protections**:
- **Token Prefixes**: Use prefixes like `myapp_` to identify token types and enable quick revocation
- **Token Rotation**: Implement automatic rotation for long-lived API keys
- **Rate Limiting**: Limit token validation attempts to prevent brute force
- **Entropy Monitoring**: Log and alert on low-entropy conditions in the RNG
- **Token Binding**: Bind tokens to client fingerprints (IP, User-Agent hash) for additional security
- **Immediate Invalidation**: Support single-use tokens for password reset and immediate revocation on suspicious activity
